ee:variables.ee:set-variable:
%dw 2.0
output application/json

var workOrder = payload.compositeResponse.body[0].records[0]

var scheduling = payload.compositeResponse.body[1].records[0]
---
{
    "codigoEmpresa": workOrder.Store__r.DealerNetExternalId__c,
    "codigoConsultor": workOrder.Owner.DealerNetCode__c,
    "dataAgendamento": scheduling.StartDate__c as DateTime {format: "yyyy-MM-dd'T'HH:mm:ss.SSSZ"} as String {format: "yyyy-MM-dd'T'HH:mm:ss"},
    "placa": workOrder.Asset.Plate__c,
    "codigoModeloVeiculo": workOrder.Asset.ModelCode__c,  
    //"codigoProspect": workOrder.Store__r.DealerNetExternalId__c,
    "codigoCliente": workOrder.Account.DealerNetExternalId__c,
//    "codigoVeiculo": workOrder.Store__r.DealerNetExternalId__c,
//    "horarioChegada": workOrder.Store__r.DealerNetExternalId__c,
    "observacao": workOrder.Description,
    "tipo": if(workOrder.Type__c == "Ativo") 1 else 0,
    "status": scheduling.Status__c,
//    "codigoAtendimento": workOrder.Store__r.DealerNetExternalId__c,
//    "numeroPreOrdem": workOrder.Store__r.DealerNetExternalId__c,
//    "motivoConsultor": workOrder.Store__r.DealerNetExternalId__c,
//    "codigoApoioUsuario": workOrder.Store__r.DealerNetExternalId__c,
    "clienteAguarda": workOrder.CustomerWaiting__c,
    "exigeLavagem": workOrder.RequiresWashing__c,
//    "entregaDomicilio": workOrder.Store__r.DealerNetExternalId__c,
    "km": workOrder.Store__r.CurrentMileage__c,
    "clienteDesejaTransporte": workOrder.CustomerNeedsTransport__c,
    "clienteServicoValet": workOrder.ValetService__c,
    "servicoExpresso": workOrder.ExpressService__c,
    "veiculoAno": workOrder.Asset.YearOfManufacture__c,
    //"codigoGrupoAgendamento": workOrder.Store__r.DealerNetExternalId__c,
    "codigoTipoServico": workOrder.WorkOrderType__r.ExternalId__c,
//    "mobilidade": workOrder.Store__r.DealerNetExternalId__c,
//    "dataPreOrdem": workOrder.Store__r.DealerNetExternalId__c,
    "chassiVeiculo": workOrder.Asset.Chassis__c,
//    "dataPedidoPecasEspeciais": workOrder.Store__r.DealerNetExternalId__c,
//    "dataPecasRecebidas": workOrder.Store__r.DealerNetExternalId__c,
//    "rebocado": workOrder.Store__r.DealerNetExternalId__c,
//    "levarPecasSubstituidas": workOrder.Store__r.DealerNetExternalId__c,
//    "clienteRetorno": workOrder.Store__r.DealerNetExternalId__c,
//    "responsavelPedidoPecasEspeciais": workOrder.Store__r.DealerNetExternalId__c,
//    "responsavelPecasRecebidas": workOrder.Store__r.DealerNetExternalId__c,
//    "valorObjetos": workOrder.Store__r.DealerNetExternalId__c,
//    "observacaoIntegracao": workOrder.Store__r.DealerNetExternalId__c,
    "inspecaoElevador": workOrder.LiftInspection__c,
//    "partSequence": workOrder.Store__r.DealerNetExternalId__c,
//    "horimet": workOrder.Store__r.DealerNetExternalId__c,
}

ee:message.ee:set-payload:
%dw 2.0
output application/json
---
{
    "consultant": {
        "workOrderId": vars.workOrderId,
        "dealerKey": vars.consultantResponse.GENERATED_KEYS
    },
    "productives": vars.aggregateProductiveResponses map (item) -> {
        "workOrderLineItemId": item.workOrderLineItemId,
        "dealerKey": item.dealerKey
    }
}

ee:variables.ee:set-variable:
%dw 2.0
output application/json
---
{
  "allOrNone": false,
  "compositeRequest": [
    {
      "method": "GET",
      "url": "/services/data/v63.0/query?q=SELECT Asset__r.ExternalId__c, Asset__r.ModelCode__c, Asset__r.Product2.Name, Asset__r.Product2.VehicleFamilyCode__c, Asset__r.StockCode__c, Asset__r.Version__c, CreatedDate, DealerNetServiceCode__c, Description, EffectiveDate, ExternalIdDealerNet__c, MainContact__r.ContactPreference__c, OrderNumber, Store__r.DealerNetExternalId__c, TotalAmount, CommissionPercentage__c FROM Order WHERE Id = '"++ vars.orderId ++"'",
      "referenceId": "OrderQuery"
    },
    {
      "method": "GET",
      "url": "/services/data/v63.0/query?q=SELECT ListPrice, OrderId, UnitPrice, Discount__c FROM OrderItem WHERE OrderId = '"++ vars.orderId ++"'",
      "referenceId": "OrderItemsQuery"
    },
    {
      "method": "GET",
      "url": "/services/data/v63.0/query?q=SELECT Id, UniqueNumber__c, ApprovedInstallmentAmount__c, CheckAgency__c, CheckingAccount__c, ConsortiumGroup__c, ConsortiumQuote__c, CreatedDate, Description__c, DueDate__c, FinancingBank__c, InterestAmount__c, LastModifiedDate, NumberInstallmentsApproved__c, Order__c, Order__r.Account.CPFCNPJ__c, PaymentCondition__r.ExternalId__c, PaymentCondition__r.Name, UsedVehicleEvaluation__r.VehiclePlate__c, UsedVehicleEvaluation__r.ExternalId__c, TYPEOF Owner WHEN User THEN DealerNetCode__c END FROM Installment__c WHERE Order__r.Id = '" ++ vars.orderId ++ "'",
      "referenceId": "InstallmentsQuery"
    }
  ]
}

%dw 2.0 output application/json var installments = payload.compositeResponse.body[2].records
var codigoProposta = vars.proposalResponse.GENERATED_KEYS
--- installments map (installment) -> { "codigoParcelaProposta": installment.UniqueNumber__c, "codigoProposta": codigoProposta, "dataVencimento": installment.DueDate__c, "valor": installment.ApprovedInstallmentAmount__c, "observacao": installment.Description__c, "valorJuros": installment.InterestAmount__c, "numeroDocumento": installment.Order.Account.CPFCNPJ__c, "codigoUsarioCriacao": installment.Owner.DealerNetCode__c, "dataCriacao": installment.CreatedDate as DateTime { format: "yyyy-MM-dd'T'HH:mm:ss.SSSZ" } as String { format: "yyyy-MM-dd'T'HH:mm:ss" }, "codigoUsuarioAlteracao": installment.Owner.DealerNetCode__c, "dataAlteracao": installment.LastModifiedDate as DateTime { format: "yyyy-MM-dd'T'HH:mm:ss.SSSZ" } as String { format: "yyyy-MM-dd'T'HH:mm:ss" }, "codigoTipoParcela": installment.PaymentCondition__r.ExternalId__c, "codigoAvaliacaoUsado": installment.UsedVehicleEvaluation__r.ExternalId__c, "placaVeiculoUsado": installment.UsedVehicleEvaluation__r.VehiclePlate__c, "grupoConsorcio": installment.ConsortiumGroup__c, "cotaConsorcio": installment.ConsortiumQuote__c, "parcelas": installment.NumberinstallmentApproved__c, "codigoBancoCheque": installment.FinancingBank__c, "agenciaCheque": installment.CheckAgency__c, "contaCorrenteCheque": installment.CheckingAccount__c, "valorParcelasFinanciamento": installment.ApprovedInstallmentAmount__c, "taxaCadastro": 0, "parcelaAbater": installment.IsTradeWithChange__c, "installmentId": installment.Id, // PropostaParcela_Codigo confirmar com o Daniel }

ee:message.ee:set-payload:
%dw 2.0
output application/json
---
{
    "proposal": {
        "orderId": vars.orderId,
        "dealerKey": vars.proposalResponse.GENERATED_KEYS
    },
    "installments": vars.aggregateInstallmentResponse map (item) -> {
        "installmentId": item.installmentId,
        "dealerKey": item.dealerKey
    }
}

ee:variables.ee:set-variable:
%dw 2.0
output application/json
---
{
  "allOrNone": false,
  "compositeRequest": [
    {
      "method": "GET",
      "url": "/services/data/v63.0/query?q=SELECT BookingCode__c, ExternalId__c, Opportunity__r.DealerNetServiceCode__c, Opportunity__r.RecordType.Name, Price, ReservationDateTime__c, ReservationExpirationDateTime__c, Status FROM Asset WHERE Id = '" ++ vars.assetId ++ "'",
      "referenceId": "AssetQuery"
    }
