ee:message.ee:set-payload:
%dw 2.0
output application/json

var asset = payload.compositeResponse.body[0].records[0]

var statusToCode = {
  "Reservado": "AUT",
  "Comprado": "AUT",
  "Disponível": "CAN"
}
---
{
    //"VeiculoReserva_Codigo": asset.BookingCode__c,
    //"VeiculoReserva_BancoPedidoCod": asset.Opportunity__r.RecordType.Name,
    "VeiculoReserva_ValorEntrada": asset.Price,
    "VeiculoReserva_DataInicial": asset.ReservationDateTime__c as DateTime {format: "yyyy-MM-dd'T'HH:mm:ss.SSSZ"} as String {format: "yyyy-MM-dd'T'HH:mm:ss"},
    "VeiculoReserva_DataFinal": asset.ReservationExpirationDateTime__c as DateTime {format: "yyyy-MM-dd'T'HH:mm:ss.SSSZ"} as String {format: "yyyy-MM-dd'T'HH:mm:ss"},
    "VeiculoReserva_Status": statusToCode[asset.Status] default null,
    "VeiculoReserva_VeiculoCod": asset.ExternalId__c,
    "Atendimento_Codigo": asset.Opportunity__r.DealerNetServiceCode__c,
}

ee:variables.ee:set-variable:
%dw 2.0
output application/json
---
{
  "allOrNone": false,
  "compositeRequest": [
    {
      "method": "GET",
      "url": "/services/data/v63.0/query?q=SELECT YearCode__c, EvaluationPreference__c, EvaluationValidityDays__c, CaminhoPrice__c, FipeValue__c, InformedValue__c, LastAutoAvaliarSync__c, ModelId__c, ModelYear__c, Name, PriceObservation__c, Renavam__c, Status__c, Store__r.ExternalId__c, Store__r.DealerNetExternalId__c, ValuationGoal__c, ValuationObs__c, ValuationValue__c, VehicleColorId__c, VehicleMileage__c, VehiclePlate__c, VehicleVIN__c, Expenses__c, TYPEOF Owner WHEN User THEN DealerNetCode__c END FROM AssessmentUsed__c WHERE Id = '" ++ vars.assesmentId ++ "'",
      "referenceId": "AssessmentUsedQuery"
    },
    {
      "method": "GET",
      "url": "/services/data/v63.0/query?q=SELECT Order__c, Quote__r.Account.ExternalId__c, Quote__r.Opportunity.DealerNetServiceCode__c FROM Installment__c WHERE UsedVehicleEvaluation__c = '" ++ vars.assesmentId ++ "' LIMIT 1",
      "referenceId": "InstallmentsQuery"
    }
  ]
}

